# coding: utf-8
import json

import click
from tabulate import tabulate

from rainbow_admin.cli import err, info
from rainbow_admin.cli.config import format_value
from rainbow_admin.cli.group import get_group_by_id_or_name


@click.group(name="table")
@click.option(
    "-g",
    "--group",
    help="table group id",
    show_envvar=True,
    envvar="RAINBOW_GROUP",
)
@click.pass_context
def table_cli(ctx, group):
    """actions about table config"""
    group_instance = get_group_by_id_or_name(ctx.obj["admin"], group)
    if group_instance is None:
        return
    if not group_instance.is_table:
        err(f"'{group}' 不是table型分组。请使用rainbow-admin config")
    ctx.obj["table"] = group_instance.table


@table_cli.command(help="list all table config")
@click.option(
    "-f",
    "--format",
    default="table",
    help="result format",
    type=click.Choice(["table", "json", "raw"]),
)
@click.option("--show-full", help="don't truncate value", is_flag=True)
@click.pass_context
def ls(ctx, show_full, format):
    table = ctx.obj["table"]
    data = table.data

    if format == "table":
        # py3.6+ dict默认有序
        info(
            f"app_id={table.admin.app_id}, group_name={table.group_name}, table_id={table.table_id} configs:"
        )
        click.echo(
            tabulate(
                [
                    [v if show_full else format_value(v) for v in i.values()]
                    for i in data
                ],
                table.headers_ch,
                tablefmt="psql",
            )
        )
    elif format == "json":
        click.echo(json.dumps(data, ensure_ascii=False, indent=4))
    elif format == "raw":
        click.echo(json.dumps(table.get_info(), ensure_ascii=False, indent=4))


@table_cli.command(help="delete row")
@click.argument("row_id", required=True, nargs=-1, type=int)
@click.pass_context
def delete(ctx, row_id):
    """delete rows by row_id, eg: delete 1 2 3"""
    table = ctx.obj["table"]
    table.delete(*row_id)
    info("删除成功")


@table_cli.command(help="add row, use 'add' directly to show usage")
@click.argument("values", nargs=-1)
@click.pass_context
def add(ctx, values):
    """add row, use add direct to show usage"""
    table = ctx.obj["table"]
    headers = table.headers[1:]
    if len(values) != len(headers):
        click.echo("Usage: add " + " ".join([f"[{i.upper()}]" for i in headers]))
        if len(values) != 0:
            err("value len != table columns len")
        return
    data = dict(zip(headers, values))
    table.add(data)
    info("添加成功")


@table_cli.command(help="update row, use 'update' directly to show usage")
@click.option("-n", "--row-id", type=int, help="which row to update")
@click.argument("values", nargs=-1)
@click.pass_context
def update(ctx, row_id, values):
    """add row, use add direct to show usage"""
    table = ctx.obj["table"]
    headers = table.headers[1:]
    if len(values) != len(headers):
        click.echo(
            "Usage: update -n ROW_ID " + " ".join([f"[{i.upper()}]" for i in headers])
        )
        if len(values) != 0:
            err("value len != table columns len")
        return
    if row_id is None:
        err("Please input row_id")
    data = dict(zip(headers, values))
    table.update(row_id, data)
    info("修改成功")


@table_cli.command(help="get table detail")
@click.option("--field", help="show only one field")
@click.option(
    "-f",
    "--format",
    default="table",
    help="result format",
    type=click.Choice(["table", "json"]),
)
@click.argument("row_id", required=True, type=int)
@click.pass_context
def get(ctx, row_id, field, format):
    table = ctx.obj["table"]
    row: dict = table.get(row_id)
    if row is None:
        err(f"未找到id={row_id}的配置")
        return
    if field:
        if field not in row:
            err(f"{field} not in {list(row.keys())}")
        else:
            click.echo(row[field])
    else:
        if format == "table":
            click.echo(tabulate([[k, v] for k, v in row.items()], tablefmt="simple"))
        elif format == "json":
            click.echo(json.dumps(row, ensure_ascii=False, indent=4))
